modelAmpm(newValue, oldValue) {
  if (newValue !== oldValue) {
    const hours = isNull(this.modelHours) ? 0 : this.modelHours
    this.$nextTick(() => {
      if (newValue === 0 && hours > 11) {
        // Switched to AM
        this.modelHours = hours - 12
      } else if (newValue === 1 && hours < 12) {
        // Switched to PM
        this.modelHours = hours + 12
      }
    })
  }
}

export function getMonthNames(locale?: string | string[], format: Intl.DateTimeFormatOptions['month'] = 'long'): string[] {
    const dates = []
    for (let i = 0; i < 12; i++) {
        dates.push(new Date(2000, i, 15))
    }
    const dtf = new Intl.DateTimeFormat(locale, {
        month: format
    })
    return dates.map((d) => dtf.format(d))
}

